module counter_4bit(clk, reset, enable, count);
    input clk;
    input reset;
    input enable;
    output reg [3:0] count;
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk) begin
        if (reset)
            count <= 4'b0000;
        else if (enable)
            count <= count + 1;
    end
endmodule
